local LMatchThreeGameBaseCtrl = LXImport(".LMatchThreeGameBaseCtrl")

---@class LMatchThreeGameLineCtrl:LMatchThreeGameBaseCtrl
local LMatchThreeGameLineCtrl = LxClass("LMatchThreeGameLineCtrl", LMatchThreeGameBaseCtrl)
-----------------------------------------------------------------

local YXTouchManager = CS.YXTouchManager
local math = math

-----------------------------------------------------------------
function LMatchThreeGameLineCtrl:LMatchThreeGameLineCtrl()
    -- 触摸的下标列表
    self._touchIndexList = {}
    self._touchIndexMap = {}
end

-- 销毁
function LMatchThreeGameLineCtrl:OnDestroy()
    self:SetLine(nil)
end

-- 初始化
function LMatchThreeGameLineCtrl:Init()
    local root = self:GetMap():GetMapTrans()
    local trans = CS.FindTrans(root, "LayerRoot/Line")
    self._lineRender = trans:GetComponent(typeof(UnityEngine.LineRenderer))
end

-- 显示线
function LMatchThreeGameLineCtrl:SetLine(posList)
    posList = posList or {}
    local count = #posList
    self._lineRender.positionCount = count
    if count == 0 then
        return
    end
    self._lineRender.positionCount = count
    for k, pos in ipairs(posList) do
        self._lineRender:SetPosition(k - 1, pos)
    end
end

-- 显示线1
function LMatchThreeGameLineCtrl:SetLine1(indexList)
    local posList = {}
    local posCtrl = self:GetCtrl("Pos")
    for _, index in ipairs(indexList) do
        local pos = posCtrl:GetPosByIndex(index)
        table.insert(posList, pos)
    end
    self:SetLine(posList)
end

-- 显示线2
function LMatchThreeGameLineCtrl:SetLine2(startIndex, indexList)
    local list = {}
    local posCtrl = self:GetCtrl("Pos")
    for k, index in ipairs(indexList) do
        if k > startIndex then
            local pos = posCtrl:GetPosByIndex(index)
            table.insert(list, pos)
        end
    end
    self:SetLine(list)
end

return LMatchThreeGameLineCtrl
